——飞机杯设定——
 {
   "ItemName": "私享共鸣杯",
   "Packaging": {
     "OuterBox": "无标识的黑色包裹。",
     "InnerBox": "深紫色高级包装盒，光滑无文字，散发诱惑气息。",
     "Contents": [
       "一套未激活的杯体（1个半身飞机杯 + 3个便携飞机杯）",
       "一份说明书",
       "四个紫色特殊收纳袋"
     ],
     "Manual": {
       "Content": {
         "ProductName": "私享共鸣杯",
         "Model": "Desire-Sync 01",
         "Material": "特殊感应传导材料",
         "PackageContents": "主体验杯 x1，便携体验杯 x3，专用收纳袋 x4，说明书 x1",
         "UsageInstructions": {
           "Step1": "选择同步方式：A(媒介同步)获取目标贴身小物件；B(文字同步)书写目标全名。",
           "Step2": "将媒介/纸片置入任意杯体底部的凹槽内，建立感官连接通道。",
           "Step3": "放入媒介后杯体自动激活连接，外观、触感、内部结构及温度**完全且实时地同步复现**目标此刻身体状态，并对目标也会产生同步刺激。",
           "Step4": "形态选择与转换：主飞机杯默认为半身形态；便携飞机杯默认为特定部位（含阴道/肛门/任意指定部位）；任意便携杯可意念转化为完整的半身形态（同一时间仅限一个）。",
           "Step5": "非连接模式：直接使用模拟通用穴道（阴道/肛门），有温感和吸吮感，使用后需自行清洁。",
           "Step6": "断开连接：取出媒介/纸片或放入收纳袋/原盒，连接即断开，杯体恢复初始状态。"
         },
         "CareAndCleaning": {
           "SyncMode": "同步模式下，内部状态实时反映目标身体，断开连接后自动恢复洁净，通常无需清洁。",
           "NonSyncMode": "非连接模式使用后，用温水和中性肥皂清洗，也可使用酒精或任意清洁剂。",
           "Storage": "妥善存放于专用收纳袋或原盒内，避光防尘。"
         },
         "Disclaimer": "警告！本产品感官连接真实且双向，使用者行为对目标身体产生即时物理影响。使用者需充分理解并自愿承担一切后果（生理/心理/人际/法律/道德）。滥用责任自负。请在私密且确保不被发现的情况下审慎使用。"
       },
       "EndMessage": "强调隐私性：'没有人会知道你在做什么，请尽情享受！'"
     }
   },
   "Appearance": {
     "Inactive": "看似普通的圆柱形硅胶杯体，材质冰凉，外观平平无奇。",
     "Active": "**完全复现**目标的身体特征：皮肤质感、温暖体温、独特气味及性器官的**当前实时形状与状态**（阴道、肛门等）。"
   },
   "ActivationMechanism": {
     "Required": "建立连接步骤。",
     "Binding": "使用目标的一件小物件（如头发、袜子）作为媒介，**或**在一张纸片上写下目标女性的全名，放入杯体底部的凹槽。"
   },
   "CoreFunction_Morphing": {
     "PrimaryForm": "半身飞机杯，实时展现从腰部到大腿的下体，包含与同步目标身体**完全一致且实时变化**的性器官（含阴唇、尿道口等完整细节）、肛门及周围皮肤细节。该产品",
     "SecondaryForms": "三个普通款式便携飞机杯，默认提供阴道和后庭同步通道，第三个可意念指定同步部位（如口腔、乳间等）。",
     "FlexibleTransformation": "任何一个便携飞机杯都可在连接状态下通过意念转化为完整的半身形态（无需额外条件），但同一时间只能有一个杯体维持半身形态。"
   },
   "CoreFunction_RealtimeSync": {
     "Principle": "目标身体对应部位的**完美复制品**，**完全且实时**同步其当下的所有生理反应。",
     "Nature": "本质上构成隐秘的感官侵犯。",
     "Mechanism": "当目标在现实中因任何原因（刺激、情绪、身体活动、自然生理周期等）导致生理状态改变（如肌肉收缩/舒张、分泌物增减、温度变化、充血程度、痉挛等）时，杯体内部会**即时、完全、精确**地同步这些变化，如目标弯腰时阴道口也会呈现出相应变化或是收缩肌肉等。",
     "TargetReaction": "由于刺激可能并非自愿，目标身体会本能作出各种复杂反应（可能包括抵抗性的剧烈收缩、因羞耻/恐惧导致的异常分泌或肌肉僵硬等），具体反应模式复杂多变，取决于其个性及当前状态。"
   },
   "Interaction_PleasureAmplification": {
     "Stimulation": "杯体所呈现的**实时、真实**的同步反应（如紧致夹吸、温热湿滑、痉挛吮吸等）为使用者带来极致且难以言喻的代入式快感。",
     "UserExperience": "提供深度的禁忌占有感和暗中操控的征服欲，每一次互动都感觉是在与目标的真实身体进行性交。"
   },
   "Interaction_LinkageEffect": {
     "Concept": "多部件组合使用可产生更复杂的联动效果，可能**同时影响使用者和同步目标**的感官体验，或放大特定感受。",
     "Examples": "主杯（半身阴道）+便携杯（后庭）；便携杯（阴道）+便携杯（口腔）。",
     "Exploration": "鼓励使用者探索不同组合方式带来的独特感官反馈和互动模式。",
     "Note": "联动效果的具体表现形式多样，供使用者自行发掘。"
   },
   "PortabilityAndStealth": {
     "Deactivation": "取出媒介/纸片，或将所有杯体放入紫色包装盒/特殊收纳袋内，即可立即断开连接，杯体恢复初始普通外观，停止对目标的感官同步。",
     "Convenience": "便携飞机杯易于携带，可在不同场合建立连接并使用。"
   }
 }
